import{_ as o,o as a,c as r,a2 as t}from"./chunks/framework.IwO0Hdn_.js";const p=JSON.parse('{"title":"[UI / PRESENTATION] F-06.1 — Listado del Catálogo de Códigos de Error","description":"","frontmatter":{},"headers":[],"relativePath":"backlog/F-06.1_error_codes_index.md","filePath":"backlog/F-06.1_error_codes_index.md","lastUpdated":null}'),d={name:"backlog/F-06.1_error_codes_index.md"};function s(n,e,c,i,l,g){return a(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="ui-presentation-f-06-1-—-listado-del-catalogo-de-codigos-de-error" tabindex="-1">[UI / PRESENTATION] F-06.1 — Listado del Catálogo de Códigos de Error <a class="header-anchor" href="#ui-presentation-f-06-1-—-listado-del-catalogo-de-codigos-de-error" aria-label="Permalink to &quot;[UI / PRESENTATION] F-06.1 — Listado del Catálogo de Códigos de Error&quot;">​</a></h1><p><strong>Épica:</strong> EPIC-06 — Catálogo de Códigos de Error (CRUD)</p><h2 id="🏷️-categoria" tabindex="-1">🏷️ Categoría <a class="header-anchor" href="#🏷️-categoria" aria-label="Permalink to &quot;🏷️ Categoría&quot;">​</a></h2><p><strong>Categoría:</strong> <code>UI / Presentation</code><strong>Secundaria:</strong> <code>Logic / Business</code><strong>Impacta en:</strong> Equipo Fullstack (Livewire + Laravel)</p><h2 id="📦-dependencias" tabindex="-1">📦 Dependencias <a class="header-anchor" href="#📦-dependencias" aria-label="Permalink to &quot;📦 Dependencias&quot;">​</a></h2><blockquote><p>Backlogs que deben estar <strong>completados</strong> antes de implementar esta feature.</p></blockquote><table tabindex="0"><thead><tr><th>Backlog</th><th>Motivo</th></tr></thead><tbody><tr><td><a href="./F-00.2_migraciones_modelos.html">F-00.2</a></td><td>Tabla <code>error_codes</code> y modelo <code>ErrorCode</code> disponibles</td></tr><tr><td><a href="./F-00.3_layout_navegacion.html">F-00.3</a></td><td>Nav con enlace &#39;Error Codes&#39; activo y layout base</td></tr><tr><td><a href="./F-05.3_autenticacion_admin.html">F-05.3</a></td><td>Rutas protegidas</td></tr><tr><td><a href="./F-05.4_api_rest_crud.html">F-05.4</a></td><td>Ruta <code>GET /error-codes</code> definida en <code>routes/web.php</code></td></tr></tbody></table><p><strong>Prioridad:</strong> <code>Must</code></p><hr><p><strong>Descripción:</strong> Como administrador del sistema Quiero ver una tabla paginada con todos los códigos de error registrados, con filtros y búsqueda Para encontrar rápidamente un código concreto y gestionar el catálogo completo</p><p><strong>Criterios de Aceptación (Checklist):</strong></p><ul><li>[ ] <strong>Escenario 1 (Tabla de error codes):</strong> Dado que accedo a la sección &quot;Error Codes&quot; desde la navegación, cuando se carga la página, entonces veo una tabla con columnas: Código, Aplicación, Nombre, Fichero, Línea, Acciones (Editar / Borrar).</li><li>[ ] <strong>Escenario 2 (Paginación):</strong> Dado que existen más de 15 error codes, cuando se renderiza la tabla, entonces aparece el paginador y los registros se muestran en páginas de 15 elementos.</li><li>[ ] <strong>Escenario 3 (Filtro por aplicación):</strong> Dado que selecciono una aplicación en el filtro &quot;App&quot;, cuando se aplica, entonces la tabla muestra solo los error codes de esa aplicación.</li><li>[ ] <strong>Escenario 4 (Búsqueda por código o nombre):</strong> Dado que escribo texto en el buscador, cuando Livewire actualiza, entonces la tabla filtra por código o nombre de error que contengan el texto buscado.</li><li>[ ] <strong>Escenario 5 (Botón Crear):</strong> Dado que pulso el botón &quot;+ Nuevo Error Code&quot;, cuando se ejecuta la acción, entonces se abre el formulario de creación (modal o página separada según diseño).</li><li>[ ] <strong>Escenario 6 (Fila clicable):</strong> Dado que pulso sobre cualquier fila de la tabla, cuando se ejecuta la acción, entonces navego al detalle/edición del error code seleccionado.</li><li>[ ] <strong>Requisito Técnico:</strong> Componente Livewire <code>ErrorCodesTable</code> en <code>resources/views/livewire/error-codes-table.blade.php</code>. Propiedades con <code>#[Url]</code>: <code>$search</code>, <code>$filterApp</code>. Ruta web <code>GET /error-codes</code> → <code>ErrorCodeController@index</code>. La consulta usa <code>ILIKE</code> (PostgreSQL) para búsqueda case-insensitive.</li></ul><hr><p><strong>MoSCoW:</strong> <code>MUST</code><strong>Sprint:</strong> Sprint 2</p><p><strong>Notas:</strong></p><ul><li>El listado de aplicaciones para el filtro se obtiene como valores distintos de <code>error_codes.app_source</code> (query <code>DISTINCT</code>).</li><li>La tabla de error codes en el wireframe se ve como la segunda pantalla (con columnas Filtrados, Error, Aplicacion, Crear, flechas de orden y filas).</li></ul>',16)])])}const b=o(d,[["render",s]]);export{p as __pageData,b as default};
